// Cancellation policy configuration
const CANCELLATION_POLICY = {
  FULL_REFUND_HOURS: 24, // Full refund if cancelled more than 24 hours before departure
  PARTIAL_REFUND_PERCENT: 50, // 50% refund if cancelled less than 24 hours before departure
  DRIVER_COMPENSATION_PERCENT: 50, // Driver gets 50% compensation for short notice cancellations
  NO_SHOW_DRIVER_COMPENSATION: 100 // Driver gets 100% if passenger doesn't show up
};

export interface CancellationResult {
  refundAmountCents: number;
  driverCompensationCents: number;
  cancellationFee: number;
  refundType: 'full' | 'partial' | 'none';
  reason: string;
}

// Calculate cancellation refund based on policy
export function calculateCancellationRefund(
  departureTime: string,
  amountCents: number,
  platformFeeCents: number,
  cancellationType: 'passenger_cancel' | 'driver_cancel' | 'no_show'
): CancellationResult {
  const now = new Date();
  const departure = new Date(departureTime);
  const hoursUntilDeparture = (departure.getTime() - now.getTime()) / (1000 * 60 * 60);

  const passengerAmount = amountCents - platformFeeCents; // Amount passenger paid minus platform fee

  switch (cancellationType) {
    case 'driver_cancel':
      // Driver cancellation: Full refund including service fees
      return {
        refundAmountCents: amountCents, // Full amount including platform fee
        driverCompensationCents: 0,
        cancellationFee: 0,
        refundType: 'full',
        reason: 'Driver cancelled - full refund including service fees'
      };

    case 'no_show':
      // Passenger no-show: Driver gets full compensation, no refund
      return {
        refundAmountCents: 0,
        driverCompensationCents: passengerAmount,
        cancellationFee: amountCents,
        refundType: 'none',
        reason: 'Passenger no-show - driver compensated for full amount'
      };

    case 'passenger_cancel':
    default:
      if (hoursUntilDeparture > CANCELLATION_POLICY.FULL_REFUND_HOURS) {
        // More than 24 hours: Full refund excluding service fees
        return {
          refundAmountCents: passengerAmount,
          driverCompensationCents: 0,
          cancellationFee: platformFeeCents,
          refundType: 'full',
          reason: `Cancelled more than ${CANCELLATION_POLICY.FULL_REFUND_HOURS} hours before departure - full refund excluding service fees`
        };
      } else {
        // Less than 24 hours: Partial refund, driver compensation
        const refundAmount = Math.round(passengerAmount * (CANCELLATION_POLICY.PARTIAL_REFUND_PERCENT / 100));
        const driverCompensation = Math.round(passengerAmount * (CANCELLATION_POLICY.DRIVER_COMPENSATION_PERCENT / 100));

        return {
          refundAmountCents: refundAmount,
          driverCompensationCents: driverCompensation,
          cancellationFee: platformFeeCents + (passengerAmount - refundAmount - driverCompensation),
          refundType: 'partial',
          reason: `Cancelled less than ${CANCELLATION_POLICY.FULL_REFUND_HOURS} hours before departure - ${CANCELLATION_POLICY.PARTIAL_REFUND_PERCENT}% refund, driver compensated ${CANCELLATION_POLICY.DRIVER_COMPENSATION_PERCENT}%`
        };
      }
  }
}

// Cancel booking with proper refund handling
export async function cancelBooking(
  bookingId: string,
  userId: string,
  reason: string,
  cancellationType: 'passenger_cancel' | 'driver_cancel' | 'no_show' = 'passenger_cancel'
) {
  console.log(`≡ƒÜ½ Starting booking cancellation: ${bookingId} by user ${userId}`);

  return await db.runTransaction(async (transaction: admin.firestore.Transaction) => {
    // Get booking details
    const bookingRef = db.collection('bookings').doc(bookingId);
    const bookingDoc = await transaction.get(bookingRef);

    if (!bookingDoc.exists) {
      throw new Error('Booking not found');
    }

    const booking = bookingDoc.data()!;

    // Verify user can cancel this booking
    if (cancellationType === 'passenger_cancel' && booking.riderId !== userId) {
      throw new Error('You can only cancel your own bookings');
    }
    if (cancellationType === 'driver_cancel' && booking.driverId !== userId) {
      throw new Error('Only the driver can cancel this booking');
    }

    // Check if booking can be cancelled
    if (!['requested', 'pending_driver', 'accepted'].includes(booking.status)) {
      throw new Error(`Cannot cancel booking with status: ${booking.status}`);
    }

    // Get ride details
    const rideRef = db.collection('rides').doc(booking.rideId);
    const rideDoc = await transaction.get(rideRef);

    if (!rideDoc.exists) {
      throw new Error('Ride not found');
    }

    const ride = rideDoc.data()!;

    // Calculate refund based on cancellation policy
    const cancellationResult = calculateCancellationRefund(
      ride.departureAt,
      booking.payment.amountCents,
      booking.payment.platformFeeCents,
      cancellationType
    );

    // Process refund if applicable
    if (cancellationResult.refundAmountCents > 0) {
      try {
        await MockPaymentService.refundPayment(booking.payment.id, cancellationResult.refundAmountCents);
      } catch (error) {
        console.error('Failed to process refund:', error);
        // Continue with cancellation even if mock refund fails
      }
    }

    // Update booking status
    const newStatus = cancellationType === 'driver_cancel' ? 'cancelled_driver' : 'cancelled_rider';
    transaction.update(bookingRef, {
      status: newStatus,
      cancellationReason: reason,
      cancelledBy: userId,
      cancelledAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      cancellationDetails: {
        type: cancellationType,
        refundAmountCents: cancellationResult.refundAmountCents,
        driverCompensationCents: cancellationResult.driverCompensationCents,
        cancellationFee: cancellationResult.cancellationFee,
        refundType: cancellationResult.refundType,
        policyReason: cancellationResult.reason
      }
    });

    // Restore seats to ride if booking was accepted
    if (booking.status === 'accepted') {
      transaction.update(rideRef, {
        seatsAvailable: ride.seatsAvailable + booking.seats,
        updatedAt: new Date().toISOString()
      });
    }

    // Create audit log
    const auditRef = db.collection('booking_audit').doc();
    transaction.set(auditRef, {
      bookingId,
      action: 'cancelled',
      userId,
      previousStatus: booking.status,
      newStatus,
      cancellationType,
      reason,
      cancellationDetails: cancellationResult,
      timestamp: new Date().toISOString()
    });

    // Send notifications
    const notificationPromises = [];

    if (cancellationType === 'passenger_cancel') {
      // Notify driver about passenger cancellation
      notificationPromises.push(
        sendNotification(booking.driverId, {
          title: 'Booking Cancelled',
          body: `A passenger cancelled their booking. ${cancellationResult.driverCompensationCents > 0 ? `You'll receive $${(cancellationResult.driverCompensationCents / 100).toFixed(2)} compensation.` : ''}`,
          type: 'booking_cancelled',
          data: {
            bookingId,
            rideId: booking.rideId,
            compensationAmount: cancellationResult.driverCompensationCents,
            reason
          }
        })
      );
    } else if (cancellationType === 'driver_cancel') {
      // Notify passenger about driver cancellation
      notificationPromises.push(
        sendNotification(booking.riderId, {
          title: 'Ride Cancelled by Driver',
          body: `Your ride has been cancelled by the driver. You'll receive a full refund including service fees ($${(cancellationResult.refundAmountCents / 100).toFixed(2)}).`,
          type: 'ride_cancelled',
          data: {
            bookingId,
            rideId: booking.rideId,
            refundAmount: cancellationResult.refundAmountCents,
            reason
          }
        })
      );
    }

    // Execute notifications after transaction
    Promise.all(notificationPromises).catch(error => {
      console.error('Failed to send cancellation notifications:', error);
    });

    console.log(`Γ£à Booking cancelled successfully:`, {
      bookingId,
      cancellationType,
      refundAmount: cancellationResult.refundAmountCents,
      driverCompensation: cancellationResult.driverCompensationCents
    });

    return {
      success: true,
      cancellationDetails: cancellationResult
    };
  });
}

// Mark passenger as no-show
export async function markNoShow(bookingId: string, driverId: string, reason: string = 'Passenger did not show up at meeting point') {
  return await cancelBooking(bookingId, driverId, reason, 'no_show');
}

// Driver cancels entire ride (affects all bookings)
export async function cancelRideByDriver(rideId: string, driverId: string, reason: string) {
  console.log(`≡ƒÜ½ Driver cancelling entire ride: ${rideId}`);

  return await db.runTransaction(async (transaction: admin.firestore.Transaction) => {
    // Get ride details
    const rideRef = db.collection('rides').doc(rideId);
    const rideDoc = await transaction.get(rideRef);

    if (!rideDoc.exists) {
      throw new Error('Ride not found');
    }

    const ride = rideDoc.data()!;

    if (ride.driverId !== driverId) {
      throw new Error('Only the driver can cancel this ride');
    }

    if (ride.status !== 'active') {
      throw new Error(`Cannot cancel ride with status: ${ride.status}`);
    }

    // Get all active bookings for this ride
    const bookingsQuery = db.collection('bookings')
      .where('rideId', '==', rideId)
      .where('status', 'in', ['requested', 'pending_driver', 'accepted']);

    const bookingsSnapshot = await bookingsQuery.get();

    // Cancel each booking with full refund
    const cancellationPromises: Promise<any>[] = [];
    bookingsSnapshot.docs.forEach((bookingDoc: admin.firestore.QueryDocumentSnapshot) => {
      const booking = bookingDoc.data();

      // Calculate full refund (driver cancellation policy)
      const cancellationResult = calculateCancellationRefund(
        ride.departureAt,
        booking.payment.amountCents,
        booking.payment.platformFeeCents,
        'driver_cancel'
      );

      // Update booking
      transaction.update(bookingDoc.ref, {
        status: 'cancelled_driver',
        cancellationReason: reason,
        cancelledBy: driverId,
        cancelledAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        cancellationDetails: {
          type: 'driver_cancel',
          refundAmountCents: cancellationResult.refundAmountCents,
          driverCompensationCents: 0,
          cancellationFee: 0,
          refundType: 'full',
          policyReason: 'Driver cancelled - full refund including service fees'
        }
      });

      // Process refund
      cancellationPromises.push(
        MockPaymentService.refundPayment(booking.payment.id, cancellationResult.refundAmountCents)
          .catch(error => console.error(`Failed to refund payment ${booking.payment.id}:`, error))
      );

      // Send notification to passenger
      cancellationPromises.push(
        sendNotification(booking.riderId, {
          title: 'Ride Cancelled by Driver',
          body: `Your ride has been cancelled by the driver. You'll receive a full refund including service fees ($${(cancellationResult.refundAmountCents / 100).toFixed(2)}).`,
          type: 'ride_cancelled',
          data: {
            bookingId: bookingDoc.id,
            rideId,
            refundAmount: cancellationResult.refundAmountCents,
            reason
          }
        }).catch(error => console.error(`Failed to notify passenger ${booking.riderId}:`, error))
      );
    });

    // Update ride status
    transaction.update(rideRef, {
      status: 'cancelled',
      cancellationReason: reason,
      cancelledBy: driverId,
      cancelledAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    });

    // Create audit log
    const auditRef = db.collection('ride_audit').doc();
    transaction.set(auditRef, {
      rideId,
      action: 'cancelled_by_driver',
      userId: driverId,
      reason,
      affectedBookings: bookingsSnapshot.docs.length,
      timestamp: new Date().toISOString()
    });

    // Execute refunds and notifications
    Promise.all(cancellationPromises).catch((error: any) => {
      console.error('Some cancellation operations failed:', error);
    });

    console.log(`Γ£à Ride cancelled by driver: ${rideId}, affected ${bookingsSnapshot.docs.length} bookings`);

    return {
      success: true,
      affectedBookings: bookingsSnapshot.docs.length
    };
  });
}

/**
 * Enhanced Firebase Cloud Functions for Carpool App Booking Flow
 * 
 * Proper Stripe Connect + PaymentIntent Flow:
 * 1. Rider books -> PaymentIntent created with capture_method=manual (funds authorized, not captured)
 * 2. Driver accepts -> Booking confirmed, funds still authorized
 * 3. Ride/Delivery completed -> PaymentIntent captured, funds transferred to driver
 * 4. Cancellations -> PaymentIntent cancelled, funds released back to customer
 */

import * as functions from 'firebase-functions';
import * as admin from 'firebase-admin';
import {
  createPaymentIntent,
  capturePaymentIntent,
  cancelPaymentIntent,
  MockStripePaymentService
} from '../payment/stripePayment';

const db = admin.firestore();

// Use mock payments in development, real Stripe in production
const USE_MOCK_PAYMENTS = !functions.config().stripe?.secret_key;

interface BookingData {
  rideId: string;
  driverId: string;
  riderId: string;
  seats: number;
  amountCents: number;
  platformFeeCents: number;
  totalCents: number;
  status: 'pending_driver' | 'confirmed' | 'declined' | 'completed' | 'cancelled';
  payment: {
    intentId: string;
    clientSecret?: string;
    status: string;
    amountCents: number;
    platformFeeCents: number;
  };
  type: 'ride' | 'delivery';
  createdAt: admin.firestore.Timestamp;
  updatedAt: admin.firestore.Timestamp;
}

interface RideData {
  driverId: string;
  origin: any;
  destination: any;
  pricePerSeatCents: number;
  seatsAvailable: number;
  status: 'upcoming' | 'active' | 'completed' | 'cancelled';
  departureAt: string;
  createdAt: admin.firestore.Timestamp;
  updatedAt: admin.firestore.Timestamp;
}

// Notification helper
async function sendNotification(
  userId: string,
  title: string,
  body: string,
  data: any = {}
): Promise<void> {
  try {
    console.log(`[notify] -> ${userId}: ${title}`);

    // Store notification in Firestore
    await db.collection('notifications').add({
      userId,
      title,
      body,
      data,
      read: false,
      type: data.type || 'system',
      createdAt: admin.firestore.FieldValue.serverTimestamp(),
    });

    // Try to send FCM notification
    const userDoc = await db.collection('users').doc(userId).get();
    const userData = userDoc.data();
    const fcmToken = userData?.fcmToken as string | undefined;

    if (fcmToken) {
      try {
        await admin.messaging().send({
          token: fcmToken,
          notification: { title, body },
          data: {
            ...data,
            timestamp: Date.now().toString(),
            userId,
          },
        });
      } catch (err) {
        console.error('[notify] FCM error', err);
      }
    }
  } catch (error) {
    console.error('[notify] error', error);
  }
}

/**
 * Step 1: Create Pending Booking with Payment Authorization
 * - Creates PaymentIntent with manual capture
 * - Funds are authorized but NOT captured
 * - Booking status: pending_driver
 */
export const createPendingBooking = functions.https.onCall(async (data, context) => {
  try {
    console.log('[createPendingBooking] Starting booking creation:', data);

    if (!context.auth) {
      throw new functions.https.HttpsError('unauthenticated', 'Must be authenticated');
    }

    const riderId = context.auth.uid;
    const { rideId, seats, type = 'ride' } = data as {
      rideId: string;
      seats: number;
      type?: 'ride' | 'delivery';
    };

    if (!rideId || !seats || seats < 1 || seats > 4) {
      throw new functions.https.HttpsError('invalid-argument', 'Invalid ride ID or seats (1-4 allowed)');
    }

    const result = await db.runTransaction(async (transaction) => {
      // Get ride details
      const rideRef = db.collection('rides').doc(rideId);
      const rideDoc = await transaction.get(rideRef);
      if (!rideDoc.exists) throw new Error('Ride not found');

      const rideData = rideDoc.data() as RideData;

      if (rideData.driverId === riderId) {
        throw new Error('Cannot book your own ride');
      }

      if (rideData.status !== 'upcoming') {
        throw new Error('Ride is not available for booking');
      }

      // CRITICAL: Check for existing bookings FIRST to prevent duplicates
      // Use a composite query to ensure we catch all possible duplicates
      const existingBookingsQuery = await transaction.get(
        db.collection('bookings')
          .where('rideId', '==', rideId)
          .where('riderId', '==', riderId)
          .where('status', 'in', ['pending_driver', 'confirmed'])
      );

      if (!existingBookingsQuery.empty) {
        const existingBooking = existingBookingsQuery.docs[0].data();
        console.log(`[createPendingBooking] DUPLICATE BOOKING PREVENTED: User ${riderId} already has ${existingBooking.status} booking for ride ${rideId}`);
        throw new Error(`You already have a ${existingBooking.status === 'pending_driver' ? 'pending' : 'confirmed'} booking for this ride`);
      }

      // CRITICAL: Calculate actual available seats by counting all active bookings
      // This must be done within the transaction to ensure consistency
      const allActiveBookingsQuery = await transaction.get(
        db.collection('bookings')
          .where('rideId', '==', rideId)
          .where('status', 'in', ['pending_driver', 'confirmed'])
      );

      let totalBookedSeats = 0;
      allActiveBookingsQuery.docs.forEach(doc => {
        const booking = doc.data();
        totalBookedSeats += booking.seats;
      });

      const actualAvailableSeats = rideData.seatsAvailable - totalBookedSeats;
      console.log(`[createPendingBooking] Seat calculation: total=${rideData.seatsAvailable}, booked=${totalBookedSeats}, available=${actualAvailableSeats}, requested=${seats}`);

      if (actualAvailableSeats < seats) {
        console.log(`[createPendingBooking] INSUFFICIENT SEATS: Only ${actualAvailableSeats} available, ${seats} requested`);
        throw new Error(`Only ${Math.max(0, actualAvailableSeats)} seats available (${totalBookedSeats} already booked)`);
      }

      // Calculate amounts
      const amountCents = rideData.pricePerSeatCents * seats;
      const platformFeeCents = Math.round(amountCents * 0.1); // 10% platform fee
      const totalCents = amountCents + platformFeeCents;

      // Get driver's Stripe account ID
      const driverDoc = await transaction.get(db.collection('users').doc(rideData.driverId));
      const driverData = driverDoc.data();

      if (!driverData?.stripeAccountId && !USE_MOCK_PAYMENTS) {
        throw new Error('Driver has not set up payments yet');
      }

      const bookingRef = db.collection('bookings').doc();
      const bookingId = bookingRef.id;

      // Create PaymentIntent (authorized, not captured)
      let paymentResult;
      if (USE_MOCK_PAYMENTS) {
        console.log('≡ƒº¬ Using mock payments for development');
        paymentResult = await MockStripePaymentService.createPaymentIntent({
          amount: totalCents,
          currency: 'usd',
          driverStripeAccountId: 'mock_account',
          rideId,
          bookingId,
          platformFeeAmount: platformFeeCents,
          type
        });
      } else {
        paymentResult = await createPaymentIntent({
          amount: totalCents,
          currency: 'usd',
          driverStripeAccountId: driverData.stripeAccountId,
          rideId,
          bookingId,
          platformFeeAmount: platformFeeCents,
          type
        });
      }

      if (!paymentResult.success) {
        throw new Error(`Payment setup failed: ${paymentResult.error}`);
      }

      // Create booking with payment authorization
      const bookingData: BookingData = {
        rideId,
        driverId: rideData.driverId,
        riderId,
        seats,
        amountCents,
        platformFeeCents,
        totalCents,
        status: 'pending_driver',
        payment: {
          intentId: paymentResult.paymentIntentId!,
          clientSecret: paymentResult.clientSecret,
          status: 'authorized', // Funds authorized, not captured
          amountCents: totalCents,
          platformFeeCents
        },
        type,
        createdAt: admin.firestore.FieldValue.serverTimestamp() as admin.firestore.Timestamp,
        updatedAt: admin.firestore.FieldValue.serverTimestamp() as admin.firestore.Timestamp,
      };

      transaction.set(bookingRef, bookingData);

      // CRITICAL: Create a booking lock to prevent race conditions
      // This creates a unique document that will fail if duplicate booking attempts occur
      const lockRef = db.collection('booking_locks').doc(`${rideId}_${riderId}`);
      transaction.set(lockRef, {
        rideId,
        riderId,
        bookingId: bookingRef.id,
        createdAt: admin.firestore.FieldValue.serverTimestamp(),
        expiresAt: admin.firestore.FieldValue.serverTimestamp(), // Will be updated with actual expiry
      });

      console.log(`Γ£à Booking created with payment authorization: ${bookingId}`);
      console.log(`≡ƒÆ│ PaymentIntent: ${paymentResult.paymentIntentId} (authorized: $${(totalCents / 100).toFixed(2)})`);

      return {
        bookingId,
        paymentIntentId: paymentResult.paymentIntentId!,
        clientSecret: paymentResult.clientSecret,
        amountCents,
        platformFeeCents,
        totalCents,
        driverId: rideData.driverId,
      };
    });

    // Send notification to driver
    await sendNotification(
      result.driverId,
      'New Booking Request! ≡ƒÜù',
      `A rider wants to book ${seats} seat(s) for $${(result.amountCents / 100).toFixed(2)}.`,
      {
        type: 'booking_request',
        bookingId: result.bookingId,
        rideId,
        riderId,
        seats,
        amount: result.amountCents,
      }
    );

    return {
      success: true,
      bookingId: result.bookingId,
      paymentIntentId: result.paymentIntentId,
      clientSecret: result.clientSecret,
      message: `Payment authorized for $${(result.totalCents / 100).toFixed(2)}. Funds will be charged when the ride is completed.`,
      amountBreakdown: {
        rideAmount: result.amountCents,
        platformFee: result.platformFeeCents,
        total: result.totalCents
      }
    };

  } catch (error: any) {
    console.error('[createPendingBooking] error:', error);
    throw new functions.https.HttpsError('internal', error.message);
  }
});

/**
 * Step 2: Driver Accept/Decline Booking
 * - If accepted: booking status -> confirmed, funds remain authorized
 * - If declined: PaymentIntent cancelled, funds released
 */
export const driverRespondBooking = functions.https.onCall(async (data, context) => {
  try {
    console.log('[driverRespondBooking] Processing response:', data);

    if (!context.auth) {
      throw new functions.https.HttpsError('unauthenticated', 'Must be authenticated');
    }

    const driverId = context.auth.uid;
    const { bookingId, action } = data as { bookingId: string; action: 'accept' | 'decline' };

    if (!bookingId || !['accept', 'decline'].includes(action)) {
      throw new functions.https.HttpsError('invalid-argument', 'Invalid booking ID or action');
    }

    const result = await db.runTransaction(async (transaction) => {
      const bookingRef = db.collection('bookings').doc(bookingId);
      const bookingDoc = await transaction.get(bookingRef);

      if (!bookingDoc.exists) throw new Error('Booking not found');

      const bookingData = bookingDoc.data() as BookingData;

      if (bookingData.driverId !== driverId) {
        throw new Error('Not authorized to respond to this booking');
      }

      if (bookingData.status !== 'pending_driver') {
        throw new Error('Booking is not pending driver response');
      }

      const rideRef = db.collection('rides').doc(bookingData.rideId);
      const rideDoc = await transaction.get(rideRef);
      const rideData = rideDoc.data() as RideData;

      if (action === 'accept') {
        // Accept booking - keep funds authorized
        transaction.update(bookingRef, {
          status: 'confirmed',
          confirmedAt: admin.firestore.FieldValue.serverTimestamp(),
          updatedAt: admin.firestore.FieldValue.serverTimestamp(),
        });

        // Update available seats
        transaction.update(rideRef, {
          seatsAvailable: rideData.seatsAvailable - bookingData.seats,
          updatedAt: admin.firestore.FieldValue.serverTimestamp(),
        });

        console.log(`Γ£à Booking accepted: ${bookingId} (funds remain authorized)`);

        return {
          action: 'accepted' as const,
          bookingId,
          bookingData,
          rideId: bookingData.rideId
        };

      } else {
        // Decline booking - cancel PaymentIntent to release funds
        let cancelResult;
        if (USE_MOCK_PAYMENTS) {
          cancelResult = await MockStripePaymentService.cancelPaymentIntent(bookingData.payment.intentId);
        } else {
          cancelResult = await cancelPaymentIntent(
            bookingData.payment.intentId,
            driverId,
            'Declined by driver'
          );
        }

        if (!cancelResult.success) {
          console.error('Failed to cancel PaymentIntent:', cancelResult.error);
          // Continue with booking decline even if payment cancellation fails
        }

        transaction.update(bookingRef, {
          status: 'declined',
          declinedAt: admin.firestore.FieldValue.serverTimestamp(),
          'payment.status': 'cancelled',
          updatedAt: admin.firestore.FieldValue.serverTimestamp(),
        });

        console.log(`Γ¥î Booking declined: ${bookingId} (PaymentIntent cancelled)`);

        return {
          action: 'declined' as const,
          bookingId,
          bookingData,
          rideId: bookingData.rideId
        };
      }
    });

    // Send notifications
    if (result.action === 'accepted') {
      await sendNotification(
        result.bookingData.riderId,
        'Booking Confirmed! ≡ƒÄë',
