/**
 * Step 3: Complete Booking and Capture Payment
 * - Driver marks ride/delivery as completed
 * - PaymentIntent is captured
 * - Funds transferred to driver, platform gets fee
 */
export const completeBooking = functions.https.onCall(async (data, context) => {
  try {
    console.log('[completeBooking] Starting completion process:', data);

    if (!context.auth) {
      throw new functions.https.HttpsError('unauthenticated', 'Must be authenticated');
    }

    const completedBy = context.auth.uid;
    const { rideId, bookingId } = data as { rideId?: string; bookingId?: string };

    if (!rideId && !bookingId) {
      throw new functions.https.HttpsError('invalid-argument', 'Either rideId or bookingId is required');
    }

    const result = await db.runTransaction(async (transaction) => {
      let bookingsToComplete: any[] = [];

      if (bookingId) {
        // Complete single booking
        const bookingDoc = await transaction.get(db.collection('bookings').doc(bookingId));
        if (!bookingDoc.exists) throw new Error('Booking not found');
        bookingsToComplete = [{ id: bookingDoc.id, ...bookingDoc.data() }];
      } else if (rideId) {
        // Complete all confirmed bookings for the ride
        const bookingsQuery = await db.collection('bookings')
          .where('rideId', '==', rideId)
          .where('status', '==', 'confirmed')
          .get();

        bookingsToComplete = bookingsQuery.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      }

      if (bookingsToComplete.length === 0) {
        throw new Error('No confirmed bookings found to complete');
      }

      // Verify authorization
      const firstBooking = bookingsToComplete[0];
      if (firstBooking.driverId !== completedBy) {
        throw new Error('Only the driver can complete bookings');
      }

      let totalRevenue = 0;
      let totalPlatformFees = 0;
      const completedBookings: any[] = [];

      // Process each booking
      for (const booking of bookingsToComplete) {
        // Capture payment
        let captureResult;
        if (USE_MOCK_PAYMENTS) {
          captureResult = await MockStripePaymentService.capturePaymentIntent(booking.payment.intentId);
        } else {
          captureResult = await capturePaymentIntent(booking.payment.intentId, completedBy);
        }

        if (!captureResult.success) {
          console.error(`Failed to capture payment for booking ${booking.id}:`, captureResult.error);
          throw new Error(`Payment capture failed: ${captureResult.error}`);
        }

        // Update booking status
        transaction.update(db.collection('bookings').doc(booking.id), {
          status: 'completed',
          completedAt: admin.firestore.FieldValue.serverTimestamp(),
          completedBy,
          'payment.status': 'captured',
          updatedAt: admin.firestore.FieldValue.serverTimestamp(),
        });

        totalRevenue += booking.amountCents;
        totalPlatformFees += booking.platformFeeCents;
        completedBookings.push(booking);

        console.log(`≡ƒÆ░ Payment captured for booking ${booking.id}: $${(booking.totalCents / 100).toFixed(2)}`);
      }

      // Update ride status if completing by rideId
      if (rideId) {
        const rideRef = db.collection('rides').doc(rideId);
        transaction.update(rideRef, {
          status: 'completed',
          completedAt: admin.firestore.FieldValue.serverTimestamp(),
          completedBy,
          totalRevenue,
          platformFees: totalPlatformFees,
          driverPayout: totalRevenue - totalPlatformFees,
          updatedAt: admin.firestore.FieldValue.serverTimestamp(),
        });
      }

      return {
        completedBookings,
        totalRevenue,
        totalPlatformFees,
        driverPayout: totalRevenue - totalPlatformFees,
        rideId: rideId || firstBooking.rideId
      };
    });

    // Send notifications
    for (const booking of result.completedBookings) {
      await sendNotification(
        booking.riderId,
        'Ride Completed! Γ£à',
        `Your ${booking.type} is complete. Payment of $${(booking.totalCents / 100).toFixed(2)} has been processed.`,
        {
          type: 'booking_completed',
          rideId: result.rideId,
          bookingId: booking.id,
          amountCharged: booking.totalCents
        }
      );
    }

    await sendNotification(
      completedBy,
      'Bookings Completed! ≡ƒÆ░',
      `${result.completedBookings.length} booking(s) completed. Payout of $${(result.driverPayout / 100).toFixed(2)} has been processed.`,
      {
        type: 'bookings_completed_driver',
        rideId: result.rideId,
        payoutAmount: result.driverPayout,
        bookingCount: result.completedBookings.length
      }
    );

    return {
      success: true,
      message: `${result.completedBookings.length} booking(s) completed and payments processed successfully!`,
      summary: {
        bookingCount: result.completedBookings.length,
        totalRevenue: result.totalRevenue,
        platformFees: result.totalPlatformFees,
        driverPayout: result.driverPayout,
      },
    };

  } catch (error: any) {
    console.error('[completeBooking] error:', error);
    throw new functions.https.HttpsError('internal', error.message);
  }
});

/**
 * Cancel Booking with Proper Payment Handling
 * - Cancels PaymentIntent to release authorized funds
 * - Updates booking status
 * - Restores seat availability if needed
 */
export const cancelBooking = functions.https.onCall(async (data, context) => {
  try {
    console.log('[cancelBooking] Processing cancellation:', data);

    if (!context.auth) {
      throw new functions.https.HttpsError('unauthenticated', 'Must be authenticated');
    }

    const userId = context.auth.uid;
    const { bookingId, reason = 'Cancelled by user' } = data as {
      bookingId: string;
      reason?: string;
    };

    if (!bookingId) {
      throw new functions.https.HttpsError('invalid-argument', 'Invalid booking ID');
    }

    await db.runTransaction(async (transaction) => {
      const bookingRef = db.collection('bookings').doc(bookingId);
      const bookingDoc = await transaction.get(bookingRef);

      if (!bookingDoc.exists) throw new Error('Booking not found');

      const bookingData = bookingDoc.data() as BookingData;

      // Verify user can cancel this booking
      if (bookingData.riderId !== userId && bookingData.driverId !== userId) {
        throw new Error('You can only cancel your own bookings');
      }

      if (!['pending_driver', 'confirmed'].includes(bookingData.status)) {
        throw new Error('Booking cannot be cancelled in current status');
      }

      // Cancel PaymentIntent to release funds
      let cancelResult;
      if (USE_MOCK_PAYMENTS) {
        cancelResult = await MockStripePaymentService.cancelPaymentIntent(bookingData.payment.intentId);
      } else {
        cancelResult = await cancelPaymentIntent(
          bookingData.payment.intentId,
          userId,
          reason
        );
      }

      if (!cancelResult.success) {
        console.error('Failed to cancel PaymentIntent:', cancelResult.error);
        // Continue with booking cancellation even if payment cancellation fails
      }

      // Update booking status
      transaction.update(bookingRef, {
        status: 'cancelled',
        cancelledAt: admin.firestore.FieldValue.serverTimestamp(),
        cancelledBy: userId,
        cancellationReason: reason,
        'payment.status': 'cancelled',
        updatedAt: admin.firestore.FieldValue.serverTimestamp(),
      });

      // Restore seats if booking was confirmed
      if (bookingData.status === 'confirmed') {
        const rideRef = db.collection('rides').doc(bookingData.rideId);
        const rideDoc = await transaction.get(rideRef);
        const rideData = rideDoc.data() as RideData;

        transaction.update(rideRef, {
          seatsAvailable: rideData.seatsAvailable + bookingData.seats,
          updatedAt: admin.firestore.FieldValue.serverTimestamp(),
        });
      }

      console.log(`Γ¥î Booking cancelled: ${bookingId} (PaymentIntent cancelled, funds released)`);
    });

    return {
      success: true,
      message: 'Booking cancelled successfully. Payment authorization has been released.',
    };

  } catch (error: any) {
    console.error('[cancelBooking] error:', error);
    throw new functions.https.HttpsError('internal', error.message);
  }
});

