import { MockPayment } from '../types';

// Mock payment processing that mirrors Stripe Connect lifecycle
export class MockPaymentService {
  private static payments = new Map<string, MockPayment>();

  // Authorize payment (equivalent to Stripe payment intent creation)
  static async authorizePayment(amountCents: number, platformFeeCents: number): Promise<MockPayment> {
    const paymentId = `mock_pi_${Date.now()}_${Math.random().toString(36).slice(2, 11)}`;

    const payment: MockPayment = {
      id: paymentId,
      status: 'mock_authorized',
      amountCents,
      platformFeeCents,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };

    this.payments.set(paymentId, payment);
    console.log(`≡ƒÆ│ Mock payment authorized: ${paymentId} for $${(amountCents / 100).toFixed(2)}`);

    return payment;
  }

  // Capture payment (equivalent to Stripe payment capture)
  static async capturePayment(paymentId: string): Promise<MockPayment> {
    const payment = this.payments.get(paymentId);
    if (!payment) {
      throw new Error(`Payment ${paymentId} not found`);
    }

    if (payment.status !== 'mock_authorized') {
      throw new Error(`Payment ${paymentId} cannot be captured. Current status: ${payment.status}`);
    }

    payment.status = 'mock_captured';
    payment.updatedAt = new Date().toISOString();

    this.payments.set(paymentId, payment);
    console.log(`≡ƒÆ░ Mock payment captured: ${paymentId}`);

    return payment;
  }

  // Void payment (equivalent to Stripe payment cancellation)
  static async voidPayment(paymentId: string): Promise<MockPayment> {
    const payment = this.payments.get(paymentId);
    if (!payment) {
      throw new Error(`Payment ${paymentId} not found`);
    }

    if (payment.status !== 'mock_authorized') {
      throw new Error(`Payment ${paymentId} cannot be voided. Current status: ${payment.status}`);
    }

    payment.status = 'voided';
    payment.updatedAt = new Date().toISOString();

    this.payments.set(paymentId, payment);
    console.log(`Γ¥î Mock payment voided: ${paymentId}`);

    return payment;
  }

  // Refund payment (equivalent to Stripe refund)
  static async refundPayment(paymentId: string, refundAmountCents?: number): Promise<MockPayment> {
    const payment = this.payments.get(paymentId);
    if (!payment) {
      throw new Error(`Payment ${paymentId} not found`);
    }

    if (payment.status !== 'mock_captured') {
      throw new Error(`Payment ${paymentId} cannot be refunded. Current status: ${payment.status}`);
    }

    const refundAmount = refundAmountCents || payment.amountCents;
    if (refundAmount > payment.amountCents) {
      throw new Error(`Refund amount $${(refundAmount / 100).toFixed(2)} exceeds payment amount $${(payment.amountCents / 100).toFixed(2)}`);
    }

    payment.status = 'refunded';
    payment.updatedAt = new Date().toISOString();

    this.payments.set(paymentId, payment);
    console.log(`≡ƒöä Mock payment refunded: ${paymentId} - $${(refundAmount / 100).toFixed(2)}`);

    return payment;
  }

  // Get payment details
  static async getPayment(paymentId: string): Promise<MockPayment | null> {
    return this.payments.get(paymentId) || null;
  }

  // Calculate platform fee
  static calculatePlatformFee(amountCents: number, feePercent: number = 10): number {
    return Math.round(amountCents * (feePercent / 100));
  }

  // Calculate driver payout (amount minus platform fee)
  static calculateDriverPayout(amountCents: number, platformFeeCents: number): number {
    return amountCents - platformFeeCents;
  }
}

