/**
 * Create PaymentIntent with manual capture for authorization
 */
export async function createPaymentIntent(params: {
  amount: number;
  currency?: string;
  driverStripeAccountId: string;
  rideId: string;
  bookingId: string;
  platformFeeAmount: number;
  type?: "ride" | "delivery";
}): Promise<StripePaymentResult> {
  const {
    amount,
    currency = "usd",
    driverStripeAccountId,
    rideId,
    bookingId,
    platformFeeAmount,
    type = "ride",
  } = params;

  try {
    if (!stripe) {
      return {
        success: false,
        error: "Stripe not configured",
      };
    }

    console.log(`≡ƒôä Creating PaymentIntent for ${type}:`, {
      amount,
      platformFeeAmount,
      driverStripeAccountId,
      rideId,
      bookingId,
    });

    const paymentIntent = await stripe.paymentIntents.create({
      amount,
      currency,
      capture_method: "manual",
      application_fee_amount: platformFeeAmount,
      transfer_data: {
        destination: driverStripeAccountId,
      },
      metadata: {
        rideId,
        bookingId,
        type,
        platformFee: platformFeeAmount.toString(),
        driverAmount: (amount - platformFeeAmount).toString(),
      },
      description: `${type === "ride" ? "Ride" : "Delivery"} booking - ${type} ${rideId}`,
      automatic_payment_methods: {
        enabled: true,
      },
    });

    await db.collection("payment_intents").doc(paymentIntent.id).set({
      paymentIntentId: paymentIntent.id,
      rideId,
      bookingId,
      driverStripeAccountId,
      amount,
      platformFee: platformFeeAmount,
      driverAmount: amount - platformFeeAmount,
      currency,
      status: "requires_payment_method",
      captureMethod: "manual",
      type,
      createdAt: admin.firestore.FieldValue.serverTimestamp(),
      updatedAt: admin.firestore.FieldValue.serverTimestamp(),
    });

    console.log(`Γ£à PaymentIntent created successfully: ${paymentIntent.id}`);

    return {
      success: true,
      paymentIntentId: paymentIntent.id,
      clientSecret: paymentIntent.client_secret,
    };
  } catch (error: any) {
    console.error("Γ¥î Error creating PaymentIntent:", error);
    return {
      success: false,
      error: error.message || "Failed to create payment intent",
    };
  }
}

/**
 * Capture PaymentIntent when ride/delivery is completed
 */
export async function capturePaymentIntent(
  paymentIntentId: string,
  completedBy: string
): Promise<StripePaymentResult> {
  try {
    if (!stripe) {
      return {
        success: false,
        error: "Stripe not configured",
      };
    }

    console.log(`≡ƒÆ░ Capturing PaymentIntent: ${paymentIntentId}`);

    const paymentDoc = await db.collection("payment_intents").doc(paymentIntentId).get();
    if (!paymentDoc.exists) {
      throw new Error("PaymentIntent record not found");
    }

    const paymentData = paymentDoc.data()!;

    const paymentIntent = await stripe.paymentIntents.retrieve(paymentIntentId);

    if (paymentIntent.status !== "requires_capture") {
      throw new Error(
        `PaymentIntent cannot be captured. Current status: ${paymentIntent.status}`
      );
    }

    await stripe.paymentIntents.capture(paymentIntentId);

    await db.collection("payment_intents").doc(paymentIntentId).update({
      status: "succeeded",
      capturedAt: admin.firestore.FieldValue.serverTimestamp(),
      capturedBy: completedBy,
      updatedAt: admin.firestore.FieldValue.serverTimestamp(),
    });

    await db.collection("payouts").add({
      paymentIntentId,
      driverId: paymentData.driverId,
      stripeAccountId: paymentData.driverStripeAccountId,
      amount: paymentData.driverAmount,
      platformFee: paymentData.platformFee,
      currency: paymentData.currency,
      rideId: paymentData.rideId,
      bookingId: paymentData.bookingId,
      type: paymentData.type,
      status: "completed",
      completedBy,
      createdAt: admin.firestore.FieldValue.serverTimestamp(),
    });

    console.log(`Γ£à PaymentIntent captured successfully: ${paymentIntentId}`);

    return {
      success: true,
      paymentIntentId,
    };
  } catch (error: any) {
    console.error("Γ¥î Error capturing PaymentIntent:", error);
    return {
      success: false,
      error: error.message || "Failed to capture payment",
    };
  }
}

/**
 * Cancel PaymentIntent for booking cancellations
 */
export async function cancelPaymentIntent(
  paymentIntentId: string,
  cancelledBy: string,
  reason: string
): Promise<StripePaymentResult> {
  try {
    if (!stripe) {
      return {
        success: false,
        error: "Stripe not configured",
      };
    }

    console.log(`Γ¥î Cancelling PaymentIntent: ${paymentIntentId}`);

    const paymentIntent = await stripe.paymentIntents.retrieve(paymentIntentId);

    if (
      !["requires_payment_method", "requires_confirmation", "requires_action", "requires_capture"].includes(
        paymentIntent.status
      )
    ) {
      throw new Error(
        `PaymentIntent cannot be cancelled. Current status: ${paymentIntent.status}`
      );
    }

    await stripe.paymentIntents.cancel(paymentIntentId, {
      cancellation_reason: "requested_by_customer",
    });

    await db.collection("payment_intents").doc(paymentIntentId).update({
      status: "canceled",
      cancelledAt: admin.firestore.FieldValue.serverTimestamp(),
      cancelledBy,
      cancellationReason: reason,
      updatedAt: admin.firestore.FieldValue.serverTimestamp(),
    });

    console.log(`Γ£à PaymentIntent cancelled successfully: ${paymentIntentId}`);

    return {
      success: true,
      paymentIntentId,
    };
  } catch (error: any) {
    console.error("Γ¥î Error cancelling PaymentIntent:", error);
    return {
      success: false,
      error: error.message || "Failed to cancel payment",
    };
  }
}

/**
 * Get PaymentIntent status
 */
export async function getPaymentIntentStatus(
  paymentIntentId: string
): Promise<{
  success: boolean;
  status?: string;
  amount?: number;
  error?: string;
}> {
  try {
    if (!stripe) {
      return {
        success: false,
        error: "Stripe not configured",
      };
    }

    const paymentIntent = await stripe.paymentIntents.retrieve(paymentIntentId);

    return {
      success: true,
      status: paymentIntent.status,
      amount: paymentIntent.amount,
    };
  } catch (error: any) {
    console.error("Error getting PaymentIntent status:", error);
    return {
      success: false,
      error: error.message,
    };
  }
}

/**
 * Mock payment service for development/testing
 */
export class MockStripePaymentService {
  private static paymentIntents = new Map<string, any>();

  static async createPaymentIntent(params: any): Promise<StripePaymentResult> {
    const mockId = `pi_mock_${Date.now()}_${Math.random().toString(36).slice(2, 11)}`;
    const mockSecret = `pi_mock_${mockId}_secret_${Math.random()
      .toString(36)
      .slice(2, 11)}`;

    const mockPaymentIntent = {
      id: mockId,
      status: "requires_capture",
      amount: params.amount,
      currency: params.currency || "usd",
      capture_method: "manual",
      client_secret: mockSecret,
      metadata: {
        rideId: params.rideId,
        bookingId: params.bookingId,
        type: params.type || "ride",
      },
      created: Math.floor(Date.now() / 1000),
    };

    this.paymentIntents.set(mockId, mockPaymentIntent);

    console.log(`≡ƒº¬ Mock PaymentIntent created: ${mockId}`);

    return {
      success: true,
      paymentIntentId: mockId,
      clientSecret: mockSecret,
    };
  }

  static async capturePaymentIntent(
    paymentIntentId: string
  ): Promise<StripePaymentResult> {
    const paymentIntent = this.paymentIntents.get(paymentIntentId);

    if (!paymentIntent) {
      return {
        success: false,
        error: "PaymentIntent not found",
      };
    }

    if (paymentIntent.status !== "requires_capture") {
      return {
        success: false,
        error: `Cannot capture PaymentIntent with status: ${paymentIntent.status}`,
      };
    }

    paymentIntent.status = "succeeded";
    paymentIntent.captured_at = Math.floor(Date.now() / 1000);

    this.paymentIntents.set(paymentIntentId, paymentIntent);

    console.log(`≡ƒº¬ Mock PaymentIntent captured: ${paymentIntentId}`);

    return {
      success: true,
      paymentIntentId,
    };
  }

  static async cancelPaymentIntent(
    paymentIntentId: string
  ): Promise<StripePaymentResult> {
    const paymentIntent = this.paymentIntents.get(paymentIntentId);

    if (!paymentIntent) {
      return {
        success: false,
        error: "PaymentIntent not found",
      };
    }

    paymentIntent.status = "canceled";
    paymentIntent.canceled_at = Math.floor(Date.now() / 1000);

    this.paymentIntents.set(paymentIntentId, paymentIntent);

    console.log(`≡ƒº¬ Mock PaymentIntent cancelled: ${paymentIntentId}`);

    return {
      success: true,
      paymentIntentId,
    };
  }
}

